    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'conditional_parameters'::text)), ARRAY[]::uuid[]) AS conditional_parameter_ids,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'departments'::text)), ARRAY[]::uuid[]) AS department_ids,
